CreateButton.example:
tab:CreateButton({
    text     = "Force Teleport",
    callback = function()
        print("Teleport button pressed.")
    end,
})

CreateColorPicker.example:
tab:CreateColorPicker({
    text     = "ESP Color",
    default  = Color3.fromRGB(255, 0, 0),
    flag     = "esp_color",
    callback = function(color)
        print("Color changed:", color)
    end,
})

CreateDropdown.example:
tab:CreateDropdown({
    text     = "Target Part",
    list     = {"Head", "Torso", "LeftArm", "RightArm"},
    default  = "Head",
    multiple = false,
    flag     = "target_part",
    callback = function(selected)
        print("Selected:", selected[1])
    end,
})

CreateInput.example:
tab:CreateInput({
    text        = "Webhook URL",
    placeholder = "https://discord.com/api/webhooks/...",
    default     = "",
    flag        = "webhook_url",
    callback    = function(url)
        print("Webhook:", url)
    end,
})

CreateKeybind.example:
tab:CreateKeybind({
    text     = "Toggle GUI",
    default  = Enum.KeyCode.RightControl,
    flag     = "gui_toggle",
    callback = function(key)
        print("Keybind triggered:", key.Name)
    end,
})

CreatePlayerList.example:
tab:CreatePlayerList({
    text   = "Active Server Players",
    height = 280,
    buttons = {
        {
            text = "TP",
            type = "button",
            callback = function(player)
                print("Teleporting to: " .. player.Name)
            end
        },
        {
            text = "ESP",
            type = "toggle",
            callback = function(player, active)
                print("ESP for " .. player.Name .. " set to " .. tostring(active))
            end
        }
    }
})

CreateSlider.example:
tab:CreateSlider({
    text     = "FOV Range",
    min      = 10,
    max      = 200,
    default  = 90,
    flag     = "aimbot_fov",
    callback = function(value)
        print("FOV:", value)
    end,
})

CreateTargetBody.example:
tab:CreateTargetBody({
    text          = "Selective Hitboxes",
    multiple      = true,
    default       = {"Head", "Torso"},
    disabledParts = {"LeftArm", "RightArm"},
    flag          = "target_hitboxes",
    callback      = function(parts)
        print("Active hitboxes:", table.concat(parts, ", "))
    end,
})

CreateToggle.example:
tab:CreateToggle({
    text     = "Silent Aim",
    default  = false,
    flag     = "silent_aim",
    callback = function(state)
        print("Silent Aim:", state)
    end,
})

Notify.example:
MonoUI.Notify({
    title    = "Success",
    content  = "Cheat successfully loaded!",
    icon     = "check-circle",
    duration = 5,
})

CreateControlHUD.example:
MonoUI.CreateControlHUD({
    { icon = "swords", default = false, callback = function(v) print("Aim:", v) end },
    { icon = "eye",    default = true,  callback = function(v) print("ESP:", v) end },
})
